SELECT COUNT(a.archive_id) FROM doc_archive a LEFT JOIN project_selection s ON a.selection_id = s.selection_id AND s.is_deleted = 0 LEFT JOIN sys_user stu ON a.student_id = stu.user_id AND stu.is_deleted = 0 LEFT JOIN project_topic pt ON s.topic_id = pt.topic_id AND pt.is_deleted = 0 WHERE a.is_deleted = 0
AND a.selection_id = #{req.selectionId}
AND s.campus_name LIKE CONCAT('%', #{req.campusName}, '%')
AND s.teacher_id = #{req.teacherId}
AND a.student_id = #{req.studentId}
AND s.academic_year LIKE CONCAT(#{req.academicYear}, '%')
AND a.stage_name LIKE CONCAT('%', #{req.stageName}, '%')
AND (stu.real_name LIKE CONCAT('%', #{req.keyword}, '%') OR stu.student_no LIKE CONCAT('%', #{req.keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{req.keyword}, '%') OR a.stage_name LIKE CONCAT('%', #{req.keyword}, '%'))

AND s.teacher_id = #{req.teacherId}
AND s.academic_year LIKE CONCAT(#{req.academicYear}, '%')
AND a.stage_name LIKE CONCAT('%', #{req.stageName}, '%')
AND (stu.real_name LIKE CONCAT('%', #{req.keyword}, '%') OR stu.student_no LIKE CONCAT('%', #{req.keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{req.keyword}, '%') OR a.stage_name LIKE CONCAT('%', #{req.keyword}, '%'))
ORDER BY a.create_time DESC LIMIT #{offset}, #{limit}
